import axios from 'axios';

export const userService = {
    async getUsers() {
        try {
            const response = await axios.get(`api/lotes`);
            return response.data;
        } catch (error) {
            console.error('Error fetching lotes:', error);
            throw error; // Re-throw to handle in component
        }
    }
}
